import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.Codec;
import java.util.Scanner;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize and escape user input using OWASP ESAPI
        Codec codec = ESAPI.encoder();
        String sanitizedInput = codec.encodeForHTML(userInput);

        // Output the sanitized user input
        System.out.println("Hello, " + sanitizedInput + "! Welcome to our website.");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
